  1017 | // match variations of a^2 + 2*a*b + b^2
  1018 | //
  1019 | // to reuse the code between the FP and Int versions, the instruction OpCodes
  1020 | //  and constant types have been turned into template parameters.
  1021 | //
  1022 | // Mul2Rhs: The constant to perform the multiplicative equivalent of X*2 with;
  1023 | //  should be `m_SpecificFP(2.0)` for FP and `m_SpecificInt(1)` for Int
  1024 | //  (we're matching `X<<1` instead of `X*2` for Int)
  1025 | template <bool FP, typename Mul2Rhs>
  1026 | static bool matchesSquareSum(BinaryOperator &I, Mul2Rhs M2Rhs, Value *&A,
  1027 |                              Value *&B) {
  1028 |   constexpr unsigned MulOp = FP ? Instruction::FMul : Instruction::Mul;
  1029 |   constexpr unsigned AddOp = FP ? Instruction::FAdd : Instruction::Add;
  1030 |   constexpr unsigned Mul2Op = FP ? Instruction::FMul : Instruction::Shl;
  1031 | 
  1032 |   // (a * a) + (((a * 2) + b) * b)
  1033 |   if (match(&I, m_c_BinOp(
  1034 |                     AddOp, m_OneUse(m_BinOp(MulOp, m_Value(A), m_Deferred(A))),
  1035 |                     m_OneUse(m_BinOp(
  1036 |                         MulOp,
  1037 |                         m_c_BinOp(AddOp, m_BinOp(Mul2Op, m_Deferred(A), M2Rhs),
  1038 |                                   m_Value(B)),
  1039 |                         m_Deferred(B))))))
  1040 |     return true;
  1041 | 
  1042 |   // ((a * b) * 2)  or ((a * 2) * b)
  1043 |   // +
  1044 |   // (a * a + b * b) or (b * b + a * a)
  1045 |   return match(
  1046 |       &I,
  1047 |       m_c_BinOp(AddOp,
  1048 |                 m_CombineOr(
  1049 |                     m_OneUse(m_BinOp(
  1050 |                         Mul2Op, m_BinOp(MulOp, m_Value(A), m_Value(B)), M2Rhs)),
  1051 |                     m_OneUse(m_BinOp(MulOp, m_BinOp(Mul2Op, m_Value(A), M2Rhs),
  1052 |                                      m_Value(B)))),
  1053 |                 m_OneUse(m_c_BinOp(
  1054 |                     AddOp, m_BinOp(MulOp, m_Deferred(A), m_Deferred(A)),
  1055 |                     m_BinOp(MulOp, m_Deferred(B), m_Deferred(B))))));
  1056 | }
  1057 | 
  1058 | // Fold integer variations of a^2 + 2*a*b + b^2 -> (a + b)^2
  1059 | Instruction *InstCombinerImpl::foldSquareSumInt(BinaryOperator &I) {
  1060 |   Value *A, *B;
  1061 |   if (matchesSquareSum</*FP*/ false>(I, m_SpecificInt(1), A, B)) {
  1062 |     Value *AB = Builder.CreateAdd(A, B);
  1063 |     return BinaryOperator::CreateMul(AB, AB);
  1064 |   }
  1065 |   return nullptr;
  1066 | }
