  1068 | // Fold floating point variations of a^2 + 2*a*b + b^2 -> (a + b)^2
  1069 | // Requires `nsz` and `reassoc`.
  1070 | Instruction *InstCombinerImpl::foldSquareSumFP(BinaryOperator &I) {
  1071 |   assert(I.hasAllowReassoc() && I.hasNoSignedZeros() && "Assumption mismatch");
  1072 |   Value *A, *B;
  1073 |   if (matchesSquareSum</*FP*/ true>(I, m_SpecificFP(2.0), A, B)) {
  1074 |     Value *AB = Builder.CreateFAddFMF(A, B, &I);
